module RefModule(
    input A,
    output Z,
    input TE,
    input VPB,
    input VPWR,
    input VGND,
    input VNB
);reg unused_Z_reg;

    always @(*) begin
        if (VGND >= VPWR) begin
            unused_Z_reg = ~A;
        end else if (TE == 1) begin
            unused_Z_reg = ~A;
        end else begin
            unused_Z_reg = A;
        end
    end

    assign Z = unused_Z_reg;

endmodule
